  E'Hi {{first_name}}, your {{vehicle}} is reserved — payment still needed.\n\nRef {{booking_code}}\nPickup {{pickup_date}} at {{pickup_time}}\n\nFinish here: {{confirm_link}}\nUnpaid bookings expire 48h after approval. — Annie''s Car Rental',
  E'automated', E'Sent 24 hours after approval when payment has not been completed.'
)
