  E'Booking Cancelled', E'booking_cancelled', E'both',
  E'Booking cancelled — {{booking_code}}',
  E'Hi {{first_name}},\n\nYour booking has been cancelled.\n\nReference: {{booking_code}}\nVehicle: {{vehicle}}\nDates: {{pickup_date}} – {{return_date}}\n\nAny deposit collected is refunded to your original payment method within 3–5 business days. Want to rebook? We''re here at (772) 207-1655.\n\nAnnie''s Car Rental\nPort St. Lucie, FL',
  E'Hi {{first_name}}, your booking for the {{vehicle}} ({{pickup_date}}–{{return_date}}) is cancelled.\n\nRef {{booking_code}}\nAny deposit is refunded within 3–5 business days.\n\nQuestions? (772) 207-1655 — Annie''s Car Rental',
  E'automated', E'Sent when a booking is cancelled.'
)
ON CONFLICT (stage) DO UPDATE SET
  name = EXCLUDED.name, channel = EXCLUDED.channel, subject = EXCLUDED.subject,
  body = EXCLUDED.body, sms_body = EXCLUDED.sms_body,
  trigger_type = EXCLUDED.trigger_type, description = EXCLUDED.description;

COMMIT;

SELECT stage, channel FROM email_templates WHERE stage IN ('booking_submitted', 'booking_approved', 'booking_declined', 'payment_confirmed', 'payment_reminder', 'insurance_approved', 'insurance_rejected', 'ready_for_pickup', 'pickup_reminder', 'day_of_pickup', 'mid_rental_checkin', 'return_reminder', 'day_of_return', 'return_confirmed', 'rental_completed', 'late_return_warning', 'late_return_escalation', 'extension_offer', 'damage_notification', 'deposit_refunded', 'deposit_settled', 'repeat_customer', 'booking_cancelled') ORDER BY stage;
